    18→  const TITLE_REF =
    19→    "recipe name, dish title, name of the food, nazwa przepisu, nazwa dania";
    20→  const HEADER_REF =
    21→    "ingredients list, cooking directions, section heading, składniki, przygotowanie, sposób wykonania";
    22→  const NOISE_REF =
    23→    "page number, table of contents, book footer, garbled text";
    24→
    25→  return async (text: string): Promise<Array<number>> => {
    26→    const lower = text.toLowerCase();
    27→
    28→    // Title reference → unit vector in dimension 0
    29→    if (lower === TITLE_REF.toLowerCase()) {
    30→      return [1, 0, 0];
    31→    }
    32→    // Header reference → unit vector in dimension 1
    33→    if (lower === HEADER_REF.toLowerCase()) {
    34→      return [0, 1, 0];
    35→    }
    36→    // Noise reference → unit vector in dimension 2 (orthogonal)
    37→    if (lower === NOISE_REF.toLowerCase()) {
    38→      return [0, 0, 1];
    39→    }
    40→
    41→    // Check if text contains title-like words → high cosine with title ref
    42→    const isTitle = titleWords.some((w) => lower.includes(w.toLowerCase()));
    43→    // Check if text contains header-like words → high cosine with header ref
    44→    const isHeader = headerWords.some((w) => lower.includes(w.toLowerCase()));
    45→
    46→    if (isTitle && !isHeader) {
